{% assign section_settings = section.settings %}

<div class="section-background color-{{ section_settings.color_scheme }}"></div>
<div
  class="section section--page-width color-{{ section_settings.color_scheme }} spacing-style"
  style="{% render 'spacing-style', settings: section_settings %}"
  data-testid="faq-accordion-{{ section.id }}"
>
  {% if section_settings.heading != blank %}
    <div class="faq-accordion__heading">
      <h2 class="faq-accordion__title">{{ section_settings.heading }}</h2>
    </div>
  {% endif %}

  {% if section.blocks.size > 0 %}
    <div class="faq-accordion__items">
      {% for block in section.blocks %}
        {% case block.type %}
          {% when 'faq-item' %}
            <details 
              class="faq-accordion__item"
              {% if block.settings.open_by_default %}open{% endif %}
              {{ block.shopify_attributes }}
            >
              <summary class="faq-accordion__question">
                {{ block.settings.question }}
                <span class="faq-accordion__icon">
                  <svg class="faq-accordion__icon-plus" width="16" height="16" viewBox="0 0 16 16" fill="none">
                    <path d="M8 1V15M1 8H15" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
                  </svg>
                  <svg class="faq-accordion__icon-minus" width="16" height="2" viewBox="0 0 16 2" fill="none">
                    <path d="M1 1H15" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
                  </svg>
                </span>
              </summary>
              <div class="faq-accordion__answer">
                {{ block.settings.answer }}
              </div>
            </details>
        {% endcase %}
      {% endfor %}
    </div>
  {% endif %}
</div>

{% stylesheet %}
  .faq-accordion__heading {
    margin-bottom: var(--padding-lg);
    text-align: center;
  }

  .faq-accordion__title {
    margin: 0;
    font-size: var(--font-h2--size);
    font-weight: var(--font-h2--weight);
    line-height: var(--font-h2--line-height);
  }

  .faq-accordion__items {
    display: flex;
    flex-direction: column;
    gap: var(--padding-xs);
  }

  .faq-accordion__item {
    border: 1px solid var(--color-border);
    border-radius: var(--border-radius);
    overflow: hidden;
  }

  .faq-accordion__question {
    padding: var(--padding-md);
    cursor: pointer;
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-weight: 600;
    background-color: var(--color-background);
    list-style: none;
    transition: background-color 0.2s ease;
  }

  .faq-accordion__question:hover {
    background-color: var(--color-background-secondary);
  }

  .faq-accordion__question::-webkit-details-marker {
    display: none;
  }

  .faq-accordion__icon {
    flex-shrink: 0;
    margin-left: var(--padding-sm);
  }

  .faq-accordion__icon-minus {
    display: none;
  }

  .faq-accordion__item[open] .faq-accordion__icon-plus {
    display: none;
  }

  .faq-accordion__item[open] .faq-accordion__icon-minus {
    display: block;
  }

  .faq-accordion__answer {
    padding: 0 var(--padding-md) var(--padding-md);
    background-color: var(--color-background);
    line-height: 1.6;
  }

  .faq-accordion__answer p {
    margin: 0 0 var(--padding-sm);
  }

  .faq-accordion__answer p:last-child {
    margin-bottom: 0;
  }
{% endstylesheet %}

{% schema %}
{
  "name": "FAQ Accordion",
  "class": "faq-accordion-section", 
  "blocks": [
    {
      "type": "faq-item",
      "name": "FAQ Item",
      "settings": [
        {
          "type": "text",
          "id": "question",
          "label": "Question",
          "default": "Frequently asked question"
        },
        {
          "type": "richtext",
          "id": "answer", 
          "label": "Answer",
          "default": "<p>Your answer goes here.</p>"
        },
        {
          "type": "checkbox",
          "id": "open_by_default",
          "label": "Open by default",
          "default": false
        }
      ]
    }
  ],
  "settings": [
    {
      "type": "text",
      "id": "heading",
      "label": "Section heading",
      "default": "Frequently Asked Questions"
    },
    {
      "type": "color_scheme",
      "id": "color_scheme",
      "label": "Color scheme",
      "default": "scheme-1"
    },
    {
      "type": "header",
      "content": "Padding"
    },
    {
      "type": "range",
      "id": "padding-block-start",
      "label": "Top",
      "min": 0,
      "max": 100,
      "step": 1,
      "unit": "px",
      "default": 40
    },
    {
      "type": "range",
      "id": "padding-block-end",
      "label": "Bottom", 
      "min": 0,
      "max": 100,
      "step": 1,
      "unit": "px",
      "default": 40
    }
  ],
  "presets": [
    {
      "name": "FAQ Accordion",
      "category": "Text",
      "blocks": [
        {
          "type": "faq-item",
          "settings": {
            "question": "What is your return policy?",
            "answer": "<p>We offer a 30-day return policy for all unused items in their original packaging.</p>"
          }
        },
        {
          "type": "faq-item", 
          "settings": {
            "question": "How long does shipping take?",
            "answer": "<p>Standard shipping takes 3-5 business days. Express shipping is available for 1-2 business day delivery.</p>"
          }
        }
      ]
    }
  ]
}
{% endschema %}

